$uid..write:
auth != null && (
            // A: The Root Administrator is allowed to update any profile (e.g. approve or delete)
            root.child('maloracity_data/users').child(auth.uid).child('role').val() === 'root' ||
            (
              // B: A user is allowed to write their own profile during initial signup
              auth.uid === $uid && (
                // B.1: If there are NO users in the database, the user becomes root and approved automatically
                (!root.child('maloracity_data/users').exists() && 
                 newData.child('role').val() === 'root' && 
                 newData.child('status').val() === 'approved') ||
                // B.2: If users already exist, the user must register as a pending editor
                (root.child('maloracity_data/users').exists() && 
                 !data.exists() && 
                 newData.child('role').val() === 'editor' && 
                 newData.child('status').val() === 'pending')
              )
            )
          )
